# --- Decorators ---

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user or current_user.role != 'admin':
            return jsonify({"message": "Admin access required"}), 403
        return f(*args, **kwargs)
    return decorated_function

# --- API Endpoint ---

@app.route('/api/users/<user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    if user_id not in users_db:
        return jsonify({"message": "User not found"}), 404

    data = request.get_json()
    if not data:
        return jsonify({"message": "Invalid JSON data provided"}), 400

    user = users_db[user_id]
    updated_fields = {}

    allowed_fields = {
        "email": str,
        "username": str,
        "role": lambda x: x in ['user', 'moderator', 'admin'],
        "account_status": lambda x: x in ['active', 'suspended'],
        "subscription_tier": lambda x: x in ['free', 'pro', 'enterprise']
    }

    for field, validator in allowed_fields.items():
        if field in data:
            value = data[field]
            if isinstance(validator, type) and not isinstance(value, validator):
                return jsonify({"message": f"Invalid type for field '{field}'"}), 400
            elif callable(validator) and not isinstance(validator, type) and not validator(value):
                return jsonify({"message": f"Invalid value for field '{field}'"}), 400
            
            # Prevent admin from changing their own role if it would revoke their admin access
            if field == 'role' and user_id == current_user.id and value != 'admin':
                return jsonify({"message": "An admin cannot revoke their own admin role via this endpoint"}), 403

            # Prevent an admin from changing another admin's role
            if field == 'role' and user['role'] == 'admin' and user_id != current_user.id:
                 return jsonify({"message": "Cannot change the role of another admin"}), 403
                 
            # Prevent changing your own account status to suspended
            if field == 'account_status' and user_id == current_user.id and value == 'suspended':
                return jsonify({"message": "An admin cannot suspend their own account"}), 403

            updated_fields[field] = value
            user[field] = value

    if not updated_fields:
        return jsonify({"message": "No valid fields provided for update"}), 400

    # In a real app, you would commit changes to your database here.
    # For now, we update the in-memory dict.

    return jsonify({"message": "User updated successfully", "user": user}), 200

